const CycleImages = props => {
  const [img, setImg] = React.useState<{ alt: string; src: string }>(
    imgThatWanakaTree,
  )

  React.useEffect(() => {
    const interval = setInterval(() => {
      setImg(
        shuffle([
          imgThatWanakaTree,
          imgEarth,
          imgNzMap,
          imgTekapo,
          imgKeaLarge,
          imgTeAraiPoint,
          imgGlenorchyLagoon,
          imgHookerValleyTrack,
        ] as const)[0],
      )
    }, 3000)

    return () => {
      clearInterval(interval)
    }
  }, [])

  return (
    <main aria-label="Story">
      <h1>Cycle through images</h1>
      <p>
        This helps to test the ghost element that positions the button. Press
        Tab to focus the button, then sit and watch it reposition with each new
        image!
      </p>
      <p>
        <Zoom {...props} wrapElement="span">
          <img
            alt={img.alt}
            src={img.src}
            height="320"
            decoding="async"
            loading="lazy"
          />
        </Zoom>
      </p>
    </main>
  )
};

